import { Link } from 'react-router-dom';
import { useState } from 'react';
import Card from '../components/Card';
import Button from '../components/Button';

const domains = [
  {
    title: 'AI & ML',
    description: 'Machine learning models, data pipelines and intelligent systems.',
    links: [
      { name: "Coursera ML", url: "https://www.coursera.org/learn/machine-learning" },
      { name: "Kaggle", url: "https://www.kaggle.com/learn" }
    ]
  },
  {
    title: 'Web Development',
    description: 'Frontend, backend, and full-stack app delivery.',
    links: [
      { name: "MDN Docs", url: "https://developer.mozilla.org" },
      { name: "FreeCodeCamp", url: "https://www.freecodecamp.org" }
    ]
  },
  {
    title: 'Cloud & DevOps',
    description: 'Cloud services automation, CI/CD, and infrastructure as code.',
    links: [
      { name: "AWS Training", url: "https://aws.amazon.com/training/" }
    ]
  },
  {
    title: 'Cybersecurity',
    description: 'Secure design, risk management, and defensive tools.',
    links: [
      { name: "Cybrary", url: "https://www.cybrary.it/" }
    ]
  }
];

export default function DomainsPage() {
  const [selectedDomain, setSelectedDomain] = useState(null);

  return (
    <div className="space-y-8">
      <Card title="Domain selection" description="Choose a specialization that best fits your goals and study rhythm. Not sure which one? Use the chatbot to get personalized recommendations.">
        
        <div className="mb-6">
          <Link to="/chatbot">
            <Button variant="ghost">Ask chatbot for domain recommendations</Button>
          </Link>
        </div>

        <div className="grid gap-5 sm:grid-cols-2 lg:grid-cols-3">
          {domains.map((domain) => (
            <div key={domain.title} className="rounded-[2rem] border border-slate-300 bg-gradient-to-br from-green-100 to-emerald-100 p-6 shadow-md hover:shadow-lg dark:border-slate-600 dark:from-slate-700 dark:to-slate-700 dark:shadow-slate-950/50">
              
              <h3 className="text-xl font-semibold text-slate-900 dark:text-slate-50">
                {domain.title}
              </h3>

              <p className="mt-3 text-slate-700 dark:text-slate-300">
                {domain.description}
              </p>

              <div
                onClick={() => setSelectedDomain(domain)}
                className="mt-5 inline-flex items-center rounded-full bg-slate-300/50 px-4 py-2 text-sm font-medium text-slate-800 dark:bg-slate-600/50 dark:text-slate-200 cursor-pointer"
              >
                Select path
              </div>

            </div>
          ))}
        </div>

        {/* Show links */}
        {selectedDomain && (
          <div className="mt-8 p-6 border rounded-[2rem]">
            <h2 className="text-xl font-semibold text-slate-900 dark:text-slate-50 mb-4">
              {selectedDomain.title} Learning Resources
            </h2>

            <ul className="space-y-2">
              {selectedDomain.links.map((link, index) => (
                <li key={index}>
                  <a
                    href={link.url}
                    target="_blank"
                    rel="noreferrer"
                    className="text-blue-600 underline"
                  >
                    {link.name}
                  </a>
                </li>
              ))}
            </ul>
          </div>
        )}

      </Card>
    </div>
  );
}
